import{_ as r,o as a,c as o,ag as l}from"./chunks/framework.CNG7EpJN.js";const u=JSON.parse('{"title":"トラブルシューティング","description":"","frontmatter":{"title":"トラブルシューティング"},"headers":[],"relativePath":"tenant/19-troubleshoot.md","filePath":"tenant/19-troubleshoot.md"}'),e={name:"tenant/19-troubleshoot.md"};function d(i,t,s,n,h,c){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="_19-トラブルシューティング" tabindex="-1">19. トラブルシューティング <a class="header-anchor" href="#_19-トラブルシューティング" aria-label="Permalink to &quot;19. トラブルシューティング&quot;">​</a></h1><p>問題が起きたときは、画面名、操作内容、表示されたメッセージ、発生時刻を確認してください。POSLAサポートへ連絡する際にも、この情報があると確認が早くなります。</p><div class="tip custom-block"><p class="custom-block-title">まず最初に: 管理画面右下の「📚 サポートガイド」を開く</p><p>管理画面右下のオレンジ色の <strong>「📚 サポートガイド」</strong> ボタンから、よくある質問や対処方法をすぐに確認できます。以下の 5 入口で答えを探せます:</p><ul><li><strong>ホーム</strong>: カテゴリ別ショートカット + 人気の質問 + エラー番号入力欄</li><li><strong>よくある質問</strong>: ログイン/注文/会計/印刷/予約/KDS/メニュー/シフト/テイクアウト/設定 のカテゴリ別 Q&amp;A</li><li><strong>キーワード検索</strong>: 「会計」「パスワード」などで横断検索</li><li><strong>症状からたどる</strong>: 「KDSに出ない」等の症状から手順を表示</li><li><strong>エラー番号</strong>: <code>E3024</code> 等を入力すると意味と対処を即表示</li></ul><p>まずはサポートガイドで該当する項目を探し、それでも解決しない場合に POSLAサポートへご連絡ください。</p></div><h2 id="まず確認すること" tabindex="-1">まず確認すること <a class="header-anchor" href="#まず確認すること" aria-label="Permalink to &quot;まず確認すること&quot;">​</a></h2><ol><li>インターネット接続を確認します。</li><li>ブラウザを再読み込みします。</li><li>別の端末またはブラウザで試します。</li><li>ログイン中のユーザーと権限を確認します。</li><li>店舗選択が正しいか確認します。</li></ol><h2 id="よくある症状" tabindex="-1">よくある症状 <a class="header-anchor" href="#よくある症状" aria-label="Permalink to &quot;よくある症状&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>確認すること</th></tr></thead><tbody><tr><td>ログインできない</td><td>ユーザー名、パスワード、アカウント状態</td></tr><tr><td>注文が届かない</td><td>Wi-Fi、KDS画面、店舗・テーブル設定</td></tr><tr><td>会計できない</td><td>注文状態、支払い方法、PIN、決済端末</td></tr><tr><td>メニューが出ない</td><td>商品の販売状態、カテゴリ、店舗表示設定</td></tr><tr><td>QRコードが読めない</td><td>印刷状態、貼り間違い、テーブル開放状態</td></tr><tr><td>レポートが合わない</td><td>期間、営業日区切り、会計済み状態</td></tr><tr><td>画面に黄色いバナーで「古いデータを表示中」と出る</td><td>通信が一時的に切れています。<strong>操作は通信復帰後に行ってください</strong>。詳細は『KDS デバイスガイド』「通信が一時的に切れた場合の挙動」</td></tr><tr><td>KDS端末状態帯が赤い</td><td>最終更新20秒超、stale、通信異常の可能性があります。Wi-Fi、端末スリープ、KDS画面が前面か、Chromeの再読み込みを確認してください</td></tr><tr><td>KDSの音声操作が効かない</td><td>KDSの <strong>音声診断</strong> でマイク権限、最後の成功、マイク入力を確認してください。必要なら <strong>音声再起動</strong> を押します</td></tr><tr><td>テイクアウトや予約が早く/遅くKDSに出る</td><td>KDSヘッダーの <strong>着手時間</strong> を確認してください。カテゴリ別設定がテイクアウト/予約設定より優先されます</td></tr></tbody></table><h2 id="poslaサポートへ連絡する前に" tabindex="-1">POSLAサポートへ連絡する前に <a class="header-anchor" href="#poslaサポートへ連絡する前に" aria-label="Permalink to &quot;POSLAサポートへ連絡する前に&quot;">​</a></h2><p>以下を控えてください。</p><ul><li>店舗名</li><li>操作した画面</li><li>操作したユーザー名</li><li>発生日時</li><li>表示されたメッセージ</li><li>可能であればスクリーンショット</li></ul><h2 id="緊急時の考え方" tabindex="-1">緊急時の考え方 <a class="header-anchor" href="#緊急時の考え方" aria-label="Permalink to &quot;緊急時の考え方&quot;">​</a></h2><p>営業中に注文や会計が止まる場合は、まず店舗の代替運用に切り替えてください。紙伝票、手書き会計、手動レジ締めなどの緊急対応を行い、営業後にPOSLAサポートへ状況をご共有ください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><p>管理画面右下の <strong>「📚 サポートガイド」</strong> (オレンジ色の丸ボタン) も利用できます。FAQ / キーワード検索 / 症状フロー / エラー番号から、必要な案内をすぐに確認できます。</p>',14)])])}const g=r(e,[["render",d]]);export{u as __pageData,g as default};
